090-system/000-templates/instant-note-sc.description:
&lt;%*
const idea = await tp.system.prompt("What's the idea?");
if (!idea) return;// Clean title: first 50 chars of the idea, avoiding cut-off words
let cleanTitle = idea.substring(0, 50).replace(/[\/:*?"&lt;&gt;|]/g, "");
if (idea.length &gt; 50) {
const lastSpace = cleanTitle.lastIndexOf(" ");
if (lastSpace &gt; 0) {
cleanTitle = cleanTitle.substring(0, lastSpace);
}
}
cleanTitle = cleanTitle.trim();const fileName = Idea - ${cleanTitle} ${tp.date.now("HHmm")};const content = `---
type: idea_capture
status: "🧠 Raw"
date_captured: ${tp.date.now("YYYY-MM-DD HH:mm")}
tags: ["idea"]
Convert to Project?
Convert to Permanent Note?
const folder = app.vault.getAbstractFileByPath("012 Idea Inbox");
await tp.file.create_new(content, fileName, true, folder);// Set the cursor programmatically in the new note
setTimeout(() =&gt; {
const activeView = app.workspace.getActiveViewOfType(tp.obsidian.MarkdownView);
const editor = activeView?.editor;
if (editor) {
const lines = editor.getValue().split("\n");
const targetLineIndex = lines.findIndex(line =&gt; line.includes("## 💭 Initial Thoughts"));
if (targetLineIndex !== -1) {
editor.setCursor({ line: targetLineIndex + 1, ch: 0 });
editor.focus();
}
}
}, 100);new Notice(Idea captured and opened from 012 Idea Inbox.);
%&gt;

090-system/000-templates/new-course-scri.description:
&lt;%*
const courseName = await tp.system.prompt("Course Name");
if (!courseName) return;const platform = await tp.system.prompt("Platform (e.g. YouTube, Coursera)", "YouTube");// 1. Fetch the Template Content
const templatePath = "090 System/000 Templates/Course MOC Template.md";
const templateFile = app.vault.getAbstractFileByPath(templatePath);
if (!templateFile) {
new Notice("Error: General Course Template not found at " + templatePath);
return;
}
let content = await app.vault.read(templateFile);// 2. Dynamic Replacements
content = content.replace(/{{title}}/g, courseName);
content = content.replace(/{{platform}}/g, platform);
content = content.replace(/{{date}}/g, tp.date.now("YYYY-MM-DD"));// 3. Folder Creation
const rootPath = 020 Courses/${courseName};
const subFolders = ["Lectures", "Assignments", "Resources"];if (!app.vault.getAbstractFileByPath(rootPath)) {
await app.vault.createFolder(rootPath);
for (const sub of subFolders) {
await app.vault.createFolder(${rootPath}/${sub});
}
}// 4. Create and Open
const mocPath = ${rootPath}/${courseName} MOC.md;
await app.vault.create(mocPath, content);
const newFile = app.vault.getAbstractFileByPath(mocPath);
await app.workspace.getLeaf().openFile(newFile);new Notice(Course ${courseName} initialized.);
%&gt;

090-system/000-templates/new-homework-sc.description:
&lt;%*
// 1. Get list of University courses (subfolders in 021 University)
const uniFolder = app.vault.getAbstractFileByPath("021 University");
if (!uniFolder || !uniFolder.children) {
new Notice("Error: 021 University folder not found.");
return;
}
const courses = uniFolder.children
.filter(c =&gt; c.children) // is a folder
.map(c =&gt; c.name)
.filter(name =&gt; name !== "Resources"); // exclude general Resources folderif (courses.length === 0) {
new Notice("No university courses found to assign homework to.");
return;
}// 2. Prompt for Course selection
const courseName = await tp.system.suggester(courses, courses);
if (!courseName) return;// 3. Prompt for Homework Name
