if (!hwName) return;// 4. Prompt for Due Date
const dueDate = await tp.system.prompt("Due Date (YYYY-MM-DD)", tp.date.now("YYYY-MM-DD", 7));
if (!dueDate) return;// Resolve subject name and paths
const startingTime = tp.date.now("YY/MM/DD, HH:mm");
const openTag = "&lt;" + "%";
const closeTag = "%" + "&gt;";// Construct the file contents
const content = `---
type: homework
subject: "<a data-href="${courseName}" href=".html" class="internal-link" target="_self" rel="noopener nofollow">${courseName}</a>"
status: 🔴 Todo
due: ${dueDate}
tags:
Academia
links:
<br>"<a data-href="021 University/${courseName}/Assignments" href=".html" class="internal-link" target="_self" rel="noopener nofollow">021 University/${courseName}/Assignments</a>"
starting time: ${startingTime}
teacher: name
progress: WIP ${openTag} tp.file.cursor() ${closeTag}
`;// Create target folder if missing
