090-system/000-templates/new-uni-course-.description:
&lt;%*
const projectName = await tp.system.prompt("University Course Name");
if (!projectName) return;// 1. Semester &amp; Academic Year Logic
const now = new Date();
const month = now.getMonth();
const year = now.getFullYear();
let semester = "";
let academicYear = "";if (month &gt;= 9 || month &lt;= 1) { // Oct (9) to Feb (1)
semester = "A";
academicYear = month &gt;= 9 ? ${year}-${year + 1} : ${year - 1}-${year};
} else if (month &gt;= 2 &amp;&amp; month &lt;= 6) { // Mar (2) to Jul (6)
semester = "B";
academicYear = ${year - 1}-${year};
} else {
semester = "Summer";
academicYear = ${year - 1}-${year};
}// 2. Fetch the Template Content
const templatePath = "090 System/000 Templates/Uni Course MOC Template.md";
const templateFile = app.vault.getAbstractFileByPath(templatePath);
if (!templateFile) {
new Notice("Error: Uni Template not found at " + templatePath);
return;
}
let content = await app.vault.read(templateFile);// 3. Dynamic Replacements
content = content.replace(/{{title}}/g, projectName);
content = content.replace(/{{semester}}/g, semester);
content = content.replace(/{{academic_year}}/g, academicYear);
content = content.replace(/{{date}}/g, tp.date.now("YYYY-MM-DD"));// 4. Folder Creation (Unified 021 University structure)
const rootPath = 021 University/${projectName};
const subFolders = ["Lectures", "Assignments", "Resources"];if (!app.vault.getAbstractFileByPath(rootPath)) {
await app.vault.createFolder(rootPath);
for (const sub of subFolders) {
await app.vault.createFolder(${rootPath}/${sub});
}
}// 5. Create and Open
const mocPath = ${rootPath}/${projectName} MOC.md;
await app.vault.create(mocPath, content);
const newFile = app.vault.getAbstractFileByPath(mocPath);
await app.workspace.getLeaf().openFile(newFile);new Notice(Enrolled in ${projectName} - Semester ${semester});
%&gt;

090-system/000-templates/smart-note-crea.description:
&lt;%*
const activeFile = tp.config.active_file;
if (!activeFile) {
new Notice("Error: No active file found.");
return;
}
const parentMOC = activeFile.basename;
const parentFolder = activeFile.parent.path;const fileCache = app.metadataCache.getFileCache(activeFile);
const mocType = fileCache?.frontmatter?.type;let templatePath = "";
let subFolder = "";
let targetType = "";// Detection Logic
if (mocType = "project_moc") {
templatePath = "090 System/000 Templates/Project Note Template.md";
subFolder = "Logs";
targetType = "project_note";
} else if (mocType = "uni_course_moc") {
templatePath = "090 System/000 Templates/Uni Lecture Template.md";
subFolder = "Lectures";
targetType = "uni_lecture";
} else if (mocType === "course_moc") {
templatePath = "090 System/000 Templates/Course Note Template.md";
subFolder = "Lectures";
targetType = "course_note";
} else {
new Notice("Error: Active note is not a valid Course or Project MOC.");
return;
}const noteName = await tp.system.prompt("Note Name");
if (!noteName) return;// Calculate next order sequence number by counting existing files of targetType
let orderDefault = "1";
const targetFolderObj = app.vault.getAbstractFileByPath(${parentFolder}/${subFolder});
if (targetFolderObj &amp;&amp; targetFolderObj.children) {
const mdFiles = targetFolderObj.children.filter(f =&gt; {
if (f.extension !== "md" &amp;&amp; !f.name.endsWith(".md")) return false;
const cache = app.metadataCache.getFileCache(f);
return cache?.frontmatter?.type === targetType;
});
orderDefault = (mdFiles.length + 1).toString();
}const order = await tp.system.prompt("Order Number", orderDefault);const templateFile = app.vault.getAbstractFileByPath(templatePath);
if (!templateFile) {
new Notice("Error: Template file not found at " + templatePath);
return;
}
let content = await app.vault.read(templateFile);// Replacements
content = content.replace(/{{title}}/g, noteName);
content = content.replace(/{{parent}}/g, parentMOC);
content = content.replace(/{{order}}/g, order);
content = content.replace(/{{date}}/g, tp.date.now("YYYY-MM-DD"));// Create subfolder if missing
const targetPath = ${parentFolder}/${subFolder};
if (!app.vault.getAbstractFileByPath(targetPath)) {
await app.vault.createFolder(targetPath);
}// Create and Open
const finalPath = ${targetPath}/${noteName}.md;
await app.vault.create(finalPath, content);
const newFile = app.vault.getAbstractFileByPath(finalPath);
await app.workspace.getLeaf().openFile(newFile);
%&gt;
